1	//! Corpus census of the record-cell wrap model (BEHAVIOR.md §3f).
2	//!
3	//! For every record in the corpus, parse its label into groups → cells, dewrap
4	//! each cell back to its flat (post-abbreviation) text, re-run several candidate
5	//! per-cell width allocators through the exact layout engine, and compare the
6	//! produced record-label bytes to the actual cell bytes. Reports byte-exactness
7	//! over wrapping prem/concl cells (the round-8 metric) and over all cells, per
8	//! allocator, in ONE corpus pass.
9	//!
10	//! Ignored by default; run with `GRAPHCLEAN_CORPUS=<dir> cargo test --release
11	//! --test fill_census -- --ignored --nocapture census`.
12	
13	use graph_clean::doclayout::wrap_cell_dot;
14	
15	fn split_top(s: &str, sep: char) -> Vec<String> {
16	    let chars: Vec<char> = s.chars().collect();
17	    let mut parts = Vec::new();
18	    let mut cur = String::new();
19	    let mut depth = 0i32;
20	    let mut i = 0;
21	    while i < chars.len() {
22	        let c = chars[i];
23	        if c == '\\' && i + 1 < chars.len() {
24	            cur.push(c);
25	            cur.push(chars[i + 1]);
26	            i += 2;
27	            continue;
28	        }
29	        match c {
30	            '{' => {
31	                depth += 1;
32	                cur.push(c);
33	            }
34	            '}' => {
35	                depth -= 1;
36	                cur.push(c);
37	            }
38	            _ if c == sep && depth == 0 => parts.push(std::mem::take(&mut cur)),
39	            _ => cur.push(c),
40	        }
41	        i += 1;
42	    }
43	    parts.push(cur);
44	    parts
45	}
46	
47	fn unescape(t: &str) -> String {
48	    t.replace("\\<", "<").replace("\\>", ">").replace("\\{", "{").replace("\\}", "}").replace("\\|", "|")
49	}
50	
51	fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
52	    if !(label.starts_with('{') && label.ends_with('}')) {
53	        return None;
54	    }
55	    let inner = &label[1..label.len() - 1];
56	    let mut groups = Vec::new();
57	    for g in split_top(inner, '|') {
58	        let g = g.trim();
59	        if !(g.starts_with('{') && g.ends_with('}')) {
60	            return None;
61	        }
62	        let gi = &g[1..g.len() - 1];
63	        groups.push(split_top(gi, '|'));
64	    }
65	    Some(groups)
66	}
67	
68	fn strip_port(cell: &str) -> Option<&str> {
69	    let rest = cell.strip_prefix("<n")?;
70	    let sp = rest.find("> ")?;
71	    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) {
72	        return None;
73	    }
74	    Some(&rest[sp + 2..])
75	}
76	
77	fn is_info_body(body: &str) -> bool {
78	    body.starts_with('#') && body.contains(" : ")
79	}
80	
81	fn dewrap(body: &str) -> String {
82	    let t = body.replace("&nbsp;", "");
83	    let t = t.replace(",\\l", ", ");
84	    let t = t.replace("\\l)", " )");
85	    let t = t.replace("\\l", "");
86	    unescape(&t)
87	}
88	
89	fn flat_width(body: &str) -> usize {
90	    let lost = body.matches(",\\l").count() + body.matches("\\l)").count();
91	    let bare = unescape(&body.replace("\\l", "").replace("&nbsp;", ""));
92	    bare.chars().count() + lost
93	}
94	
95	const FLOOR: usize = 20;
96	const W: usize = 87;
97	
98	// ---- candidate allocators: given the group's cell flats, per-cell width ----
99	
100	fn alloc_smallest_first(flats: &[usize]) -> Vec<usize> {
101	    let n = flats.len();
102	    let mut order: Vec<usize> = (0..n).collect();
103	    order.sort_by_key(|&i| flats[i]);
104	    let mut occ = flats.to_vec();
105	    let mut out = vec![0usize; n];
106	    for &i in &order {
107	        let others: usize = (0..n).filter(|&j| j != i).map(|j| occ[j]).sum();
108	        let b = W.saturating_sub(others).max(FLOOR);
109	        out[i] = b;
110	        occ[i] = flats[i].min(b);
111	    }
112	    out
113	}
114	
115	fn alloc_flatsum(flats: &[usize]) -> Vec<usize> {
116	    let t: usize = flats.iter().sum();
117	    (0..flats.len())
118	        .map(|i| W.saturating_sub(t - flats[i]).max(FLOOR))
119	        .collect()
120	}
121	
122	fn alloc_proportional(flats: &[usize]) -> Vec<usize> {
123	    let t: usize = flats.iter().sum();
124	    if t == 0 {
125	        return vec![W; flats.len()];
126	    }
127	    flats
128	        .iter()
129	        .map(|&f| ((W * f + t / 2) / t).max(FLOOR))
130	        .collect()
131	}
132	
133	fn alloc_prop_l(flats: &[usize], l: usize) -> Vec<usize> {
134	    let t: usize = flats.iter().sum();
135	    if t == 0 {
136	        return vec![W; flats.len()];
137	    }
138	    flats.iter().map(|&f| ((l * f + t / 2) / t).max(FLOOR)).collect()
139	}
140	
141	fn alloc_prop_ceil(flats: &[usize]) -> Vec<usize> {
142	    let t: usize = flats.iter().sum();
143	    if t == 0 {
144	        return vec![W; flats.len()];
145	    }
146	    flats.iter().map(|&f| ((W * f + t - 1) / t).max(FLOOR)).collect()
147	}
148	
149	/// Reserve cells whose flat ≤ FLOOR (they never wrap) at their flat width, then
150	/// distribute the remaining budget proportionally among the larger cells.
151	fn alloc_reserve_small(flats: &[usize]) -> Vec<usize> {
152	    let reserved: usize = flats.iter().filter(|&&f| f <= FLOOR).sum();
153	    let big_sum: usize = flats.iter().filter(|&&f| f > FLOOR).sum();
154	    if big_sum == 0 {
155	        return flats.iter().map(|&f| f.max(FLOOR)).collect();
156	    }
157	    let avail = W.saturating_sub(reserved).max(FLOOR);
158	    flats
159	        .iter()
160	        .map(|&f| {
161	            if f <= FLOOR {
162	                FLOOR
163	            } else {
164	                ((avail * f + big_sum / 2) / big_sum).max(FLOOR)
165	            }
166	        })
167	        .collect()
168	}
169	
170	struct Tally {
171	    name: String,
172	    wrap_total: usize,
173	    wrap_match: usize,
174	    all_total: usize,
175	    all_match: usize,
176	    // diagnostics (single vs multi cell groups; failure modes)
177	    single_wrap_total: usize,
178	    single_wrap_match: usize,
179	    multi_wrap_total: usize,
180	    multi_wrap_match: usize,
181	    // mismatch modes on wrapping cells
182	    fn_predict_oneline: usize, // actual wraps, predicted single line (false neg)
183	    fill_error: usize,         // both wrap, differ
184	    fp_examples: Vec<(String, usize, String, String)>, // flat, width, want, got
185	}
186	
187	fn main_census() {
188	    let Ok(corpus) = std::env::var("GRAPHCLEAN_CORPUS") else {
189	        eprintln!("set GRAPHCLEAN_CORPUS");
190	        return;
191	    };
192	    type Alloc = (&'static str, Box<dyn Fn(&[usize]) -> Vec<usize>>);
193	    let allocs: Vec<Alloc> = vec![
194	        ("proportional(87)", Box::new(alloc_proportional)),
195	        ("prop_ceil", Box::new(alloc_prop_ceil)),
196	        ("reserve_small", Box::new(alloc_reserve_small)),
197	        ("prop(89)", Box::new(|f: &[usize]| alloc_prop_l(f, 89))),
198	    ];
199	    let _ = (alloc_smallest_first, alloc_flatsum, alloc_prop_l);
200	    let mut tallies: Vec<Tally> = allocs
201	        .iter()
202	        .map(|(n, _)| Tally {
203	            name: n.to_string(),
204	            wrap_total: 0,
205	            wrap_match: 0,
206	            all_total: 0,
207	            all_match: 0,
208	            single_wrap_total: 0,
209	            single_wrap_match: 0,
210	            multi_wrap_total: 0,
211	            multi_wrap_match: 0,
212	            fn_predict_oneline: 0,
213	            fill_error: 0,
214	            fp_examples: Vec::new(),
215	        })
216	        .collect();
217	
218	    let step: usize = std::env::var("STEP").ok().and_then(|s| s.parse().ok()).unwrap_or(1);
219	    for (fi, entry) in std::fs::read_dir(&corpus).unwrap().enumerate() {
220	        if step > 1 && fi % step != 0 {
221	            continue;
222	        }
223	        let path = entry.unwrap().path();
224	        if path.extension().and_then(|e| e.to_str()) != Some("dot") {
225	            continue;
226	        }
227	        let dot = std::fs::read_to_string(&path).unwrap();
228	        for line in dot.lines() {
229	            if !line.contains("shape=\"record\"") {
230	                continue;
231	            }
232	            let Some(lstart) = line.find("label=\"") else { continue };
233	            let after = &line[lstart + 7..];
234	            let Some(lend) = after.find("\",fillcolor") else { continue };
235	            let label = &after[..lend];
236	            let Some(groups) = parse_record(label) else { continue };
237	            for cells in &groups {
238	                let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
239	                    Some(b) => b,
240	                    None => continue,
241	                };
242	                if bodies.iter().any(|b| is_info_body(b)) {
243	                    continue;
244	                }
245	                let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
246	                let flat_texts: Vec<String> = bodies.iter().map(|b| dewrap(b)).collect();
247	                let single = bodies.len() == 1;
248	                for (ti, (_, alloc)) in allocs.iter().enumerate() {
249	                    let widths = alloc(&flats);
250	                    for (k, body) in bodies.iter().enumerate() {
251	                        let predicted = wrap_cell_dot(&flat_texts[k], widths[k] as isize);
252	                        let is_wrap = body.contains("\\l");
253	                        let m = predicted == *body;
254	                        tallies[ti].all_total += 1;
255	                        if m {
256	                            tallies[ti].all_match += 1;
257	                        }
258	                        if is_wrap {
259	                            tallies[ti].wrap_total += 1;
260	                            if m {
261	                                tallies[ti].wrap_match += 1;
262	                            }
263	                            if single {
264	                                tallies[ti].single_wrap_total += 1;
265	                                if m {
266	                                    tallies[ti].single_wrap_match += 1;
267	                                }
268	                            } else {
269	                                tallies[ti].multi_wrap_total += 1;
270	                                if m {
271	                                    tallies[ti].multi_wrap_match += 1;
272	                                }
273	                            }
274	                            if !m {
275	                                if !predicted.contains("\\l") {
276	                                    tallies[ti].fn_predict_oneline += 1;
277	                                    if tallies[ti].fp_examples.len() < 25 && single {
278	                                        tallies[ti].fp_examples.push((
279	                                            flat_texts[k].clone(),
280	                                            widths[k],
281	                                            body.to_string(),
282	                                            predicted.clone(),
283	                                        ));
284	                                    }
285	                                } else {
286	                                    tallies[ti].fill_error += 1;
287	                                }
288	                            }
289	                        }
290	                    }
291	                }
292	            }
293	        }
294	    }
295	    for t in &tallies {
296	        eprintln!(
297	            "{:16} wrap {:>6}/{:<6}={:6.2}% | single {:>6}/{:<6}={:6.2}% | multi {:>6}/{:<6}={:6.2}% | falseNeg {:>5} fillErr {:>5}",
298	            t.name,
299	            t.wrap_match,
300	            t.wrap_total,
301	            100.0 * t.wrap_match as f64 / t.wrap_total.max(1) as f64,
302	            t.single_wrap_match,
303	            t.single_wrap_total,
304	            100.0 * t.single_wrap_match as f64 / t.single_wrap_total.max(1) as f64,
305	            t.multi_wrap_match,
306	            t.multi_wrap_total,
307	            100.0 * t.multi_wrap_match as f64 / t.multi_wrap_total.max(1) as f64,
308	            t.fn_predict_oneline,
309	            t.fill_error,
310	        );
311	    }
312	    if std::env::var("SHOW_FP").is_ok() {
313	        // single-cell false-negatives for the proportional allocator (index 2)
314	        for (flat, w, want, got) in tallies[2].fp_examples.iter().take(20) {
315	            eprintln!("--- single-cell falseNeg  w={w}  flat({}): {flat}", flat.chars().count());
316	            eprintln!("    want: {want}");
317	            eprintln!("    got : {got}");
318	        }
319	    }
320	}
321	
322	#[test]
323	#[ignore]
324	fn census() {
325	    main_census();
326	}
