1	//! Measure the CEILING for a width-based model: fraction of multi-cell wrapping
2	//! cells reproducible at SOME width (non-empty band). Also test candidate
3	//! allocators against the per-cell band. Ignored; GRAPHCLEAN_CORPUS set.
4	
5	use graph_clean::doclayout::wrap_cell_dot;
6	
7	fn split_top(s: &str, sep: char) -> Vec<String> {
8	    let ch: Vec<char> = s.chars().collect();
9	    let mut parts = Vec::new();
10	    let mut cur = String::new();
11	    let mut depth = 0i32;
12	    let mut i = 0;
13	    while i < ch.len() {
14	        let c = ch[i];
15	        if c == '\\' && i + 1 < ch.len() { cur.push(c); cur.push(ch[i + 1]); i += 2; continue; }
16	        match c {
17	            '{' => { depth += 1; cur.push(c); }
18	            '}' => { depth -= 1; cur.push(c); }
19	            _ if c == sep && depth == 0 => parts.push(std::mem::take(&mut cur)),
20	            _ => cur.push(c),
21	        }
22	        i += 1;
23	    }
24	    parts.push(cur);
25	    parts
26	}
27	fn unescape(t: &str) -> String {
28	    t.replace("\\<", "<").replace("\\>", ">").replace("\\{", "{").replace("\\}", "}").replace("\\|", "|")
29	}
30	fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
31	    if !(label.starts_with('{') && label.ends_with('}')) { return None; }
32	    let inner = &label[1..label.len() - 1];
33	    let mut groups = Vec::new();
34	    for g in split_top(inner, '|') {
35	        let g = g.trim();
36	        if !(g.starts_with('{') && g.ends_with('}')) { return None; }
37	        groups.push(split_top(&g[1..g.len() - 1], '|'));
38	    }
39	    Some(groups)
40	}
41	fn strip_port(cell: &str) -> Option<&str> {
42	    let rest = cell.strip_prefix("<n")?;
43	    let sp = rest.find("> ")?;
44	    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) { return None; }
45	    Some(&rest[sp + 2..])
46	}
47	fn is_info_body(b: &str) -> bool { b.starts_with('#') && b.contains(" : ") }
48	fn dewrap(b: &str) -> String {
49	    unescape(&b.replace("&nbsp;", "").replace(",\\l", ", ").replace("\\l)", " )").replace("\\l", ""))
50	}
51	fn flat_width(b: &str) -> usize {
52	    let lost = b.matches(",\\l").count() + b.matches("\\l)").count();
53	    unescape(&b.replace("\\l", "").replace("&nbsp;", "")).chars().count() + lost
54	}
55	fn band(flat: &str, body: &str) -> (usize, usize) {
56	    let mut lo = 0;
57	    let mut hi = 0;
58	    for w in 15..=95isize {
59	        if wrap_cell_dot(flat, w) == body {
60	            if lo == 0 { lo = w as usize; }
61	            hi = w as usize;
62	        }
63	    }
64	    (lo, hi)
65	}
66	
67	// allocators
68	fn a_prop(flats: &[usize], i: usize) -> usize {
69	    let t: usize = flats.iter().sum();
70	    ((87 * flats[i]) as f64 / t as f64).round().max(20.0) as usize
71	}
72	fn a_clamped(flats: &[usize], i: usize, c: usize) -> usize {
73	    // 87 - sum over others of min(flat_j, c), floor 20
74	    let s: usize = flats.iter().enumerate().filter(|(j, _)| *j != i).map(|(_, &f)| f.min(c)).sum();
75	    87usize.saturating_sub(s).max(20)
76	}
