78	#[test]
79	#[ignore]
80	fn width_probe() {
81	    let Ok(corpus) = std::env::var("GRAPHCLEAN_CORPUS") else { return };
82	    let sample: usize = std::env::var("SAMPLE").ok().and_then(|s| s.parse().ok()).unwrap_or(4000);
83	    let mut files: Vec<_> = std::fs::read_dir(&corpus).unwrap().map(|e| e.unwrap().path()).collect();
84	    files.sort();
85	    // sample across the whole corpus, not just the first files
86	    let step = (files.len() / 400).max(1);
87	
88	    let mut multi_wrap = 0usize;
89	    let mut has_band = 0usize;
90	    // candidate hits
91	    let mut hit_prop = 0usize;
92	    let mut hit_c8 = 0usize;
93	    let mut hit_c12 = 0usize;
94	    let mut hit_c16 = 0usize;
95	    let mut hit_c20 = 0usize;
96	    let mut hit_best = 0usize; // any width in band (ceiling)
97	    let mut done = 0usize;
98	
99	    'outer: for (fi, path) in files.iter().enumerate() {
100	        if fi % step != 0 { continue; }
101	        if path.extension().and_then(|e| e.to_str()) != Some("dot") { continue; }
102	        let dot = std::fs::read_to_string(path).unwrap();
103	        for line in dot.lines() {
104	            if !line.contains("shape=\"record\"") { continue; }
105	            let Some(ls) = line.find("label=\"") else { continue };
106	            let after = &line[ls + 7..];
107	            let Some(le) = after.find("\",fillcolor") else { continue };
108	            let Some(groups) = parse_record(&after[..le]) else { continue };
109	            for cells in &groups {
110	                let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
111	                    Some(b) => b, None => continue,
112	                };
113	                if bodies.len() < 2 || bodies.iter().any(|b| is_info_body(b)) { continue; }
114	                let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
115	                for (k, body) in bodies.iter().enumerate() {
116	                    if !body.contains("\\l") { continue; }
117	                    multi_wrap += 1;
118	                    let flat = dewrap(body);
119	                    let (lo, hi) = band(&flat, body);
120	                    let inband = |w: usize| lo > 0 && lo <= w && w <= hi;
121	                    if lo > 0 { has_band += 1; hit_best += 1; }
122	                    if inband(a_prop(&flats, k)) { hit_prop += 1; }
123	                    if inband(a_clamped(&flats, k, 8)) { hit_c8 += 1; }
124	                    if inband(a_clamped(&flats, k, 12)) { hit_c12 += 1; }
125	                    if inband(a_clamped(&flats, k, 16)) { hit_c16 += 1; }
126	                    if inband(a_clamped(&flats, k, 20)) { hit_c20 += 1; }
127	                    done += 1;
128	                    if done >= sample { break 'outer; }
129	                }
130	            }
131	        }
132	    }
133	    let p = |x: usize| 100.0 * x as f64 / multi_wrap.max(1) as f64;
134	    eprintln!("multi-cell wrapping cells sampled: {multi_wrap}");
135	    eprintln!("  reproducible at SOME width (ceiling): {has_band} = {:.1}%", p(has_band));
136	    eprintln!("  proportional(87):   {hit_prop} = {:.1}%", p(hit_prop));
137	    eprintln!("  clamped C=8:        {hit_c8} = {:.1}%", p(hit_c8));
138	    eprintln!("  clamped C=12:       {hit_c12} = {:.1}%", p(hit_c12));
139	    eprintln!("  clamped C=16:       {hit_c16} = {:.1}%", p(hit_c16));
140	    eprintln!("  clamped C=20:       {hit_c20} = {:.1}%", p(hit_c20));
141	}
