137	/// `<e1, …, en>` — the elements fill and align one past the `<`; the `>` is a
138	/// fill element nested back one column so it stays beside the last element when
139	/// it fits and peels under the `<` otherwise.
140	fn tuple_doc(inner: &str) -> Doc {
141	    let elems = split_top_commas(inner);
142	    let n = elems.len();
143	    let mut toks: Vec<Doc> = Vec::with_capacity(n + 1);
144	    for (i, e) in elems.iter().enumerate() {
145	        let d = arg_doc(e);
146	        if i + 1 < n {
147	            toks.push(beside_op(d, text(", ")));
148	        } else {
149	            toks.push(d);
150	        }
151	    }
152	    toks.push(nest(-1, &pchar('>')));
153	    beside_op(pchar('<'), fcat(toks))
154	}
