156	/// `Name( a, b, … )` — the argument list is a comma-punctuated `fsep` opening
157	/// after `Name( `; the outer `sep [ …, ) ]` drops the closing `)` to its own line
158	/// exactly when the argument fill wraps.
159	fn fact_doc(name: &str, args: &[String]) -> Doc {
160	    if args.is_empty() {
161	        return text(&format!("{}( )", name));
162	    }
163	    let n = args.len();
164	    let toks: Vec<Doc> = args
165	        .iter()
166	        .enumerate()
167	        .map(|(i, a)| {
168	            let d = arg_doc(a);
169	            if i + 1 < n {
170	                beside_op(d, text(","))
171	            } else {
172	                d
173	            }
174	        })
175	        .collect();
176	    let args_doc = fsep(toks);
177	    let opened = beside_op(text(&format!("{}( ", name)), args_doc);
178	    sep(vec![opened, text(")")])
179	}
