181	/// `#t : Rule[a1, …]` — the action list is a `vcat` (one action per line) inside
182	/// `[ … ]`; `#t : Rule` with no actions is bare text.
183	fn info_doc(flat: &str) -> Doc {
184	    let Some(open) = flat.find('[') else {
185	        return text(flat);
186	    };
187	    if !flat.ends_with(']') {
188	        return text(flat);
189	    }
190	    let prefix = &flat[..open + 1]; // "#t : Rule["
191	    let inner = &flat[open + 1..flat.len() - 1];
192	    let actions = split_top_commas(inner);
193	    let n = actions.len();
194	    let action_docs: Vec<Doc> = actions
195	        .iter()
196	        .enumerate()
197	        .map(|(i, a)| {
198	            // Each action is a fact that may itself fill-wrap; non-final actions
199	            // carry a trailing comma.
200	            let d = fact_from_flat(a);
201	            if i + 1 < n {
202	                beside_op(d, text(","))
203	            } else {
204	                d
205	            }
206	        })
207	        .collect();
208	    beside_op(beside_op(text(prefix), vcat(action_docs)), text("]"))
209	}
