260	/// Render a cell's flat text to physical lines `(indent, content)` at the given
261	/// fit **budget** (ribbon), via the layout engine. `indent` is the count of
262	/// leading spaces the engine emitted (→ `&nbsp;` in the record label); `content`
263	/// is the line with that indentation stripped, still un-escaped. The cell fits on
264	/// one line iff its flat width ≤ `budget`; the line length is
265	/// [`budget_line_len`]`(budget)` (= 1.5·budget) so wrapping is ragged (§3f).
266	pub fn layout_lines(flat: &str, budget: isize) -> Vec<(usize, String)> {
267	    layout_lines_lr(flat, budget_line_len(budget), RIBBONS)
268	}
