286	/// Like [`wrap_cell_dot`] but with an explicit line length and ribbons-per-line.
287	pub fn wrap_cell_dot_lr(flat: &str, line_len: isize, ribbons_per_line: f64) -> String {
288	    let lines = layout_lines_lr(flat, line_len, ribbons_per_line);
289	    if lines.len() == 1 && lines[0].0 == 0 {
290	        return crate::render::escape_record(&lines[0].1);
291	    }
292	    let mut out = String::new();
293	    for (indent, content) in &lines {
294	        out.push_str(&"&nbsp;".repeat(*indent));
295	        out.push_str(&crate::render::escape_record(content));
296	        out.push_str("\\l");
297	    }
298	    out
299	}
