//! Corpus constraint extractor (round 9): for every prem/concl record group in
//! the corpus, compute per cell the SET of line lengths (engine L-space,
//! ribbonsPerLine = 1.5) at which the exact layout engine reproduces the
//! observed record-cell bytes. Emits one TSV line per group:
//!
//!   file  kind(P|C)  info_flat  prem_flats  concl_flats  cells
//!
//! where `cells` is `|`-joined per-cell entries `flat:STATUS` with STATUS one of
//!   F<lo>        cell does not wrap; it matches at every L >= lo (lo = min)
//!   lo-hi[,..]   cell wraps; the L runs at which the engine output == bytes
//!   NONE         cell wraps; no L in [8, fitL] reproduces it (cell-doc gap)
//!
//! Groups dumped: multi-cell groups with any wrapping cell OR flat total > 80
//! (boundary/false-positive evidence), and single-cell wrapping groups.
//! Usage: band_dump <corpus_dir>... > bands.tsv

use graph_clean::doclayout::wrap_cell_dot_lr;
use std::collections::HashMap;

fn split_top(s: &str, sep: char) -> Vec<String> {
    let ch: Vec<char> = s.chars().collect();
    let mut parts = Vec::new();
    let mut cur = String::new();
    let mut depth = 0i32;
    let mut i = 0;
    while i < ch.len() {
        let c = ch[i];
        if c == '\\' && i + 1 < ch.len() {
            cur.push(c);
            cur.push(ch[i + 1]);
            i += 2;
            continue;
        }
        match c {
            '{' => {
                depth += 1;
                cur.push(c);
            }
            '}' => {
                depth -= 1;
                cur.push(c);
            }
            _ if c == sep && depth == 0 => parts.push(std::mem::take(&mut cur)),
            _ => cur.push(c),
        }
        i += 1;
    }
    parts.push(cur);
    parts
}
fn unescape(t: &str) -> String {
    t.replace("\\<", "<").replace("\\>", ">").replace("\\{", "{").replace("\\}", "}").replace("\\|", "|")
}
fn parse_record(label: &str) -> Option<Vec<Vec<String>>> {
    if !(label.starts_with('{') && label.ends_with('}')) {
        return None;
    }
    let inner = &label[1..label.len() - 1];
    let mut groups = Vec::new();
    for g in split_top(inner, '|') {
        let g = g.trim();
        if !(g.starts_with('{') && g.ends_with('}')) {
            return None;
        }
        groups.push(split_top(&g[1..g.len() - 1], '|'));
    }
    Some(groups)
}
fn strip_port(cell: &str) -> Option<&str> {
    let rest = cell.strip_prefix("<n")?;
    let sp = rest.find("> ")?;
    if !rest[..sp].chars().all(|c| c.is_ascii_digit()) {
        return None;
    }
    Some(&rest[sp + 2..])
}
fn is_info_body(b: &str) -> bool {
    b.starts_with('#') && b.contains(" : ")
}
fn dewrap(b: &str) -> String {
    unescape(&b.replace("&nbsp;", "").replace(",\\l", ", ").replace("\\l)", " )").replace("\\l", ""))
}
fn flat_width(b: &str) -> usize {
    let lost = b.matches(",\\l").count() + b.matches("\\l)").count();
    unescape(&b.replace("\\l", "").replace("&nbsp;", "")).chars().count() + lost
}

/// Smallest L (line length at ribbons 1.5) whose ribbon >= flat.
fn fit_l(flat: usize) -> isize {
    let mut l = ((flat as f64) * 1.5).floor() as isize - 2;
    if l < 8 {
        l = 8;
    }
    loop {
        // banker's round of L/1.5, as the engine computes the ribbon
        let v = l as f64 / 1.5;
        let fl = v.floor();
        let r = if (v - fl - 0.5).abs() < 1e-9 {
            let f = fl as i64;
            if f % 2 == 0 {
                f
            } else {
                f + 1
            }
        } else {
            v.round() as i64
        };
        if r >= flat as i64 {
            return l;
        }
        l += 1;
    }
}

/// STATUS string for one cell (see module docs).
fn cell_status(flat_text: &str, body: &str, flat: usize) -> String {
    let wraps = body.contains("\\l");
    if !wraps {
        // valid L set is [lo, +inf) (monotone: below the fit boundary the doc
        // wraps, above it renders flat; an unbreakable atom matches everywhere)
        let hi = fit_l(flat) + 2;
        let matches = |l: isize| wrap_cell_dot_lr(flat_text, l, 1.5) == body;
        if matches(8) {
            return "F8".to_string();
        }
        let (mut lo, mut hi) = (8isize, hi);
        // invariant: !matches(lo), matches(hi)
        if !matches(hi) {
            return "FNONE".to_string();
        }
        while hi - lo > 1 {
            let mid = (lo + hi) / 2;
            if matches(mid) {
                hi = mid;
            } else {
                lo = mid;
            }
        }
        return format!("F{}", hi);
    }
    // wrapping: sweep 8 ..= fitL (at/above fitL the render is one line != body)
    let top = fit_l(flat);
    let mut runs: Vec<(isize, isize)> = Vec::new();
    let mut cur: Option<(isize, isize)> = None;
    for l in 8..=top {
        if wrap_cell_dot_lr(flat_text, l, 1.5) == body {
            cur = Some(match cur {
                Some((a, _)) => (a, l),
                None => (l, l),
            });
        } else if let Some(r) = cur.take() {
            runs.push(r);
        }
    }
    if let Some(r) = cur {
        runs.push(r);
    }
    if runs.is_empty() {
        return "NONE".to_string();
    }
    runs.iter().map(|(a, b)| format!("{}-{}", a, b)).collect::<Vec<_>>().join(",")
}

fn process_file(path: &std::path::Path, cache: &mut HashMap<(String, String), String>) -> Vec<String> {
    let mut out = Vec::new();
    let Ok(dot) = std::fs::read_to_string(path) else { return out };
    let base = path.file_name().unwrap().to_string_lossy().to_string();
    for line in dot.lines() {
        if !line.contains("shape=\"record\"") {
            continue;
        }
        let Some(ls) = line.find("label=\"") else { continue };
        let after = &line[ls + 7..];
        let Some(le) = after.find("\",fillcolor") else { continue };
        let Some(groups) = parse_record(&after[..le]) else { continue };
        // locate the info group; groups before = P, after = C
        let mut info_idx = None;
        let mut info_flat = 0usize;
        for (gi, cells) in groups.iter().enumerate() {
            if cells.len() == 1 {
                if let Some(b) = strip_port(&cells[0]) {
                    if is_info_body(b) {
                        info_idx = Some(gi);
                        info_flat = flat_width(b);
                    }
                }
            }
        }
        let Some(info_idx) = info_idx else { continue };
        let group_flats: Vec<Option<Vec<usize>>> = groups
            .iter()
            .map(|cells| {
                cells
                    .iter()
                    .map(|c| strip_port(c).map(flat_width))
                    .collect::<Option<Vec<usize>>>()
            })
            .collect();
        let flats_str = |gi: usize| -> String {
            if gi >= groups.len() {
                return String::new();
            }
            match &group_flats[gi] {
                Some(v) => v.iter().map(|f| f.to_string()).collect::<Vec<_>>().join(","),
                None => String::new(),
            }
        };
        // premise group (if any) is the group before info; conclusion after
        let prem_gi = if info_idx > 0 { Some(info_idx - 1) } else { None };
        let concl_gi = if info_idx + 1 < groups.len() { Some(info_idx + 1) } else { None };
        for (kind, gi) in [("P", prem_gi), ("C", concl_gi)] {
            let Some(gi) = gi else { continue };
            let cells = &groups[gi];
            let bodies: Vec<&str> = match cells.iter().map(|c| strip_port(c)).collect::<Option<Vec<_>>>() {
                Some(b) => b,
                None => continue,
            };
            if bodies.iter().any(|b| is_info_body(b)) {
                continue;
            }
            let flats: Vec<usize> = bodies.iter().map(|b| flat_width(b)).collect();
            let total: usize = flats.iter().sum();
            let any_wrap = bodies.iter().any(|b| b.contains("\\l"));
            let dump = if bodies.len() >= 2 {
                any_wrap || total > 80
            } else {
                any_wrap
            };
            if !dump {
                continue;
            }
            let mut cellfields = Vec::with_capacity(bodies.len());
            for (k, body) in bodies.iter().enumerate() {
                let flat_text = dewrap(body);
                let key = (flat_text.clone(), body.to_string());
                let status = if let Some(s) = cache.get(&key) {
                    s.clone()
                } else {
                    let s = cell_status(&flat_text, body, flats[k]);
                    cache.insert(key, s.clone());
                    s
                };
                cellfields.push(format!("{}:{}", flats[k], status));
            }
            out.push(format!(
                "{}\t{}\t{}\t{}\t{}\t{}",
                base,
                kind,
                info_flat,
                prem_gi.map(flats_str).unwrap_or_default(),
                concl_gi.map(flats_str).unwrap_or_default(),
                cellfields.join("|")
            ));
        }
    }
    out
}

fn main() {
    let dirs: Vec<String> = std::env::args().skip(1).collect();
    let mut files: Vec<std::path::PathBuf> = Vec::new();
    for d in &dirs {
        for e in std::fs::read_dir(d).unwrap() {
            let p = e.unwrap().path();
            if p.extension().and_then(|e| e.to_str()) == Some("dot") {
                files.push(p);
            }
        }
    }
    files.sort();
    let nthreads = 8usize;
    let chunks: Vec<Vec<std::path::PathBuf>> = (0..nthreads)
        .map(|t| files.iter().skip(t).step_by(nthreads).cloned().collect())
        .collect();
    let handles: Vec<_> = chunks
        .into_iter()
        .map(|chunk| {
            std::thread::spawn(move || {
                let mut cache = HashMap::new();
                let mut out = Vec::new();
                for p in chunk {
                    out.extend(process_file(&p, &mut cache));
                }
                out
            })
        })
        .collect();
    let mut all = Vec::new();
    for h in handles {
        all.extend(h.join().unwrap());
    }
    all.sort();
    let mut so = String::new();
    for l in all {
        so.push_str(&l);
        so.push('\n');
    }
    print!("{}", so);
}

#!/usr/bin/env python3
"""Fit the per-group width allocation against corpus-derived L-space bands.

Input: bands.tsv from band_dump (file kind info_flat prem_flats concl_flats cells)
Each cell entry: flat:STATUS, STATUS in {F<lo>, FNONE, NONE, lo-hi[,lo-hi...]}.
Constraint semantics for an allocator that assigns line length L_i to cell i:
  F<lo>  -> ok iff L_i >= lo
  runs   -> ok iff L_i inside a run
  NONE   -> never ok (cell-doc ceiling exclusion; tracked separately)
"""
import sys
from collections import Counter, defaultdict

def parse(path):
    groups = []
    with open(path) as f:
        for line in f:
            parts = line.rstrip("\n").split("\t")
            if len(parts) != 6:
                continue
            fname, kind, info_flat, pf, cf, cells = parts
            cellrecs = []
            for c in cells.split("|"):
                flat_s, status = c.split(":", 1)
                flat = int(flat_s)
                if status.startswith("F"):
                    lo = None if status == "FNONE" else int(status[1:])
                    cellrecs.append((flat, "fit", lo))
                elif status == "NONE":
                    cellrecs.append((flat, "wrap", None))
                else:
                    runs = []
                    for r in status.split(","):
                        a, b = r.split("-")
                        runs.append((int(a), int(b)))
                    cellrecs.append((flat, "wrap", runs))
            groups.append({
                "file": fname, "kind": kind, "info": int(info_flat),
                "pf": [int(x) for x in pf.split(",")] if pf else [],
                "cf": [int(x) for x in cf.split(",")] if cf else [],
                "cells": cellrecs,
            })
    return groups

def rib_to_L(b):
    return (3 * b) // 2

def ok(cell, L):
    flat, k, x = cell
    if k == "fit":
        return x is not None and L >= x
    if x is None:
        return False
    return any(a <= L <= b for a, b in x)

# ---------------- allocator families (ribbon space unless noted) -------------

def rnd_half(x):  # round half away from zero (matches (W*f + t/2)//t for ints)
    import math
    return math.floor(x + 0.5)

def alloc_prop(flats, W=87, floor=20, rnd=rnd_half):
    t = sum(flats)
    if t == 0:
        return [W] * len(flats)
    return [max(rnd(W * f / t), floor) for f in flats]

def alloc_prop_floor_r(flats, W=87, floor=20):
    import math
    t = sum(flats)
    return [max(math.floor(W * f / t), floor) for f in flats]

def alloc_prop_ceil_r(flats, W=87, floor=20):
    import math
    t = sum(flats)
    return [max(math.ceil(W * f / t), floor) for f in flats]

def alloc_prop_redist(flats, W=87, floor=20):
    """Clamp-at-floor then renormalize the rest (iterate to fixpoint)."""
    n = len(flats)
    fixed = {}
    while True:
        rest = [i for i in range(n) if i not in fixed]
        if not rest:
            break
        t = sum(flats[i] for i in rest)
        w = W - sum(fixed.values())
        if t == 0 or w <= 0:
            for i in rest:
                fixed[i] = floor
            break
        newly = [i for i in rest if w * flats[i] / t < floor]
        if not newly:
            for i in rest:
                fixed[i] = max(rnd_half(w * flats[i] / t), floor)
            break
        for i in newly:
            fixed[i] = floor
    return [fixed[i] for i in range(n)]

def alloc_fitfix(flats, W=87, floor=20):
    """Cells whose share covers their flat are fixed at flat; redistribute."""
    n = len(flats)
    fixed = {}
    while True:
        rest = [i for i in range(n) if i not in fixed]
        if not rest:
            break
        t = sum(flats[i] for i in rest)
        w = W - sum(fixed.values())
        if t == 0 or w <= 0:
            for i in rest:
                fixed[i] = floor
            break
        newly = [i for i in rest if max(rnd_half(w * flats[i] / t), floor) >= flats[i]]
        if not newly:
            for i in rest:
                fixed[i] = max(rnd_half(w * flats[i] / t), floor)
            break
        for i in newly:
            fixed[i] = flats[i]
    return [fixed[i] for i in range(n)]

def eval_alloc(groups, fn, space="ribbon", ctx=False):
    """Returns (band_hits, band_total, fit_viol, fit_total, none_count)."""
    hits = tot = fviol = ftot = nones = 0
    for g in groups:
        flats = [c[0] for c in g["cells"]]
        if len(flats) < 2:
            continue
        if ctx:
            Ls = fn(flats, g)
        else:
            Ls = fn(flats)
        if space == "ribbon":
            Ls = [rib_to_L(b) for b in Ls]
        for c, L in zip(g["cells"], Ls):
            if c[1] == "wrap":
                if c[2] is None:
                    nones += 1
                    continue
                tot += 1
                if ok(c, L):
                    hits += 1
            else:
                ftot += 1
                if not ok(c, L):
                    fviol += 1
    return hits, tot, fviol, ftot, nones

def report(name, r):
    hits, tot, fviol, ftot, nones = r
    allwrap = tot + nones
    print(f"{name:34s} band-hit {hits:>6}/{tot:<6}={100*hits/max(tot,1):6.2f}%  "
          f"incl-NONE {100*hits/max(allwrap,1):6.2f}%  "
          f"fit-viol {fviol:>5}/{ftot:<6}={100*fviol/max(ftot,1):5.2f}%")

if __name__ == "__main__":
    groups = parse(sys.argv[1] if len(sys.argv) > 1 else "bands.tsv")
    multi = [g for g in groups if len(g["cells"]) >= 2]
    single = [g for g in groups if len(g["cells"]) == 1]
    wrap_multi = sum(1 for g in multi for c in g["cells"] if c[1] == "wrap")
    none_multi = sum(1 for g in multi for c in g["cells"] if c[1] == "wrap" and c[2] is None)
    wrap_single = sum(1 for g in single for c in g["cells"] if c[1] == "wrap")
    none_single = sum(1 for g in single for c in g["cells"] if c[1] == "wrap" and c[2] is None)
    print(f"groups: {len(groups)} (multi {len(multi)}, single-dumped {len(single)})")
    print(f"multi wrapping cells: {wrap_multi}, band-NONE {none_multi} "
          f"(ceiling {100*(wrap_multi-none_multi)/max(wrap_multi,1):.2f}%)")
    print(f"single wrapping cells: {wrap_single}, band-NONE {none_single} "
          f"(ceiling {100*(wrap_single-none_single)/max(wrap_single,1):.2f}%)")

    report("prop(87,f20,half)", eval_alloc(multi, lambda f: alloc_prop(f)))
    report("prop(87,f20,floor)", eval_alloc(multi, lambda f: alloc_prop_floor_r(f)))
    report("prop(87,f20,ceil)", eval_alloc(multi, lambda f: alloc_prop_ceil_r(f)))
    report("prop_redist(87,f20)", eval_alloc(multi, lambda f: alloc_prop_redist(f)))
    report("fitfix(87,f20)", eval_alloc(multi, lambda f: alloc_fitfix(f)))
    for W in (85, 86, 88, 89, 90):
        report(f"prop({W},f20,half)", eval_alloc(multi, lambda f, W=W: alloc_prop(f, W=W)))
    for fl in (15, 18, 22, 25):
        report(f"prop(87,f{fl},half)", eval_alloc(multi, lambda f, fl=fl: alloc_prop(f, floor=fl)))

#!/usr/bin/env python3
"""Test b_i = 87 - mw_j (sibling observed max line width) on 2-cell rows.

Uses bands.tsv for the b_i bands and re-reads the corpus for observed mw.
Prints hit rates of several residual identities against the bands.
"""
import sys, os, math
from collections import Counter
from fit import parse
from rowstats import parse_file, is_info, cell_lines, flat_width

def rib(L):
    v = L / 1.5
    fl = math.floor(v)
    if abs(v - fl - 0.5) < 1e-9:
        return fl if fl % 2 == 0 else fl + 1
    return round(v)

def main():
    bands_path, corpus = sys.argv[1], sys.argv[2]
    groups = parse(bands_path)
    # index bands by (file, kind, tuple(flats))
    bidx = {}
    for g in groups:
        flats = tuple(c[0] for c in g["cells"])
        bidx[(g["file"], g["kind"], flats)] = g
    stats = Counter()
    ex = []
    files = sorted(set(g["file"] for g in groups if len(g["cells"]) == 2))
    step = max(1, len(files) // 800)
    for fi, fn in enumerate(files):
        if fi % step:
            continue
        path = os.path.join(corpus, fn)
        if not os.path.exists(path):
            continue
        for recs in parse_file(path):
            info_idx = None
            for gi, cells in enumerate(recs):
                if len(cells) == 1 and is_info(cells[0]):
                    info_idx = gi
            if info_idx is None:
                continue
            for gi, cells in enumerate(recs):
                if gi == info_idx or len(cells) != 2 or any(c is None for c in cells):
                    continue
                if any(is_info(c) for c in cells):
                    continue
                if not any("\\l" in c for c in cells):
                    continue
                kind = "P" if gi < info_idx else "C"
                flats = tuple(flat_width(c) for c in cells)
                g = bidx.get((fn, kind, flats))
                if g is None:
                    continue
                mws = [max(cell_lines(c)) for c in cells]
                hs = [len(cell_lines(c)) for c in cells]
                for i in (0, 1):
                    c = g["cells"][i]
                    j = 1 - i
                    if c[1] != "wrap" or c[2] is None:
                        continue
                    lo, hi = c[2][0][0], c[2][-1][1]
                    rlo, rhi = rib(lo), rib(hi)
                    stats["cells"] += 1
                    # candidate identities, ribbon space
                    for name, val in (
                        ("87-mw_sib", 87 - mws[j]),
                        ("87-mw_sib,fl20", max(87 - mws[j], 20)),
                        ("87-flat_sib,fl20", max(87 - flats[j], 20)),
                        ("prop87", max(round(87 * flats[i] / sum(flats)), 20)),
                        ("mw_self", mws[i]),
                    ):
                        if rlo <= val <= rhi:
                            stats[name] += 1
                    if len(ex) < 25 and not (rlo <= max(87 - mws[j], 20) <= rhi):
                        ex.append((fn, kind, flats, i, (rlo, rhi), mws, hs))
    print("2-cell wrapping cells tested:", stats["cells"])
    for k in ("87-mw_sib", "87-mw_sib,fl20", "87-flat_sib,fl20", "prop87", "mw_self"):
        print(f"  {k:20s}: {stats[k]} = {100*stats[k]/max(stats['cells'],1):.1f}%")
    print("\nmisses of 87-mw_sib,fl20 (file kind flats i band mws heights):")
    for e in ex:
        print("  ", e)

