/// The shared state of a [`Doc::Lazy`] thunk.
pub struct LazyDoc(RefCell<LazyState>);

enum LazyState {
    Pending(Option<Box<dyn FnOnce() -> Doc>>),
    Forced(Doc),
}

impl std::fmt::Debug for LazyDoc {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match &*self.0.borrow() {
            LazyState::Pending(_) => write!(f, "Lazy(<pending>)"),
            LazyState::Forced(d) => write!(f, "Lazy({:?})", d),
        }
    }
}

use Doc::*;

fn rc(d: Doc) -> Rc<Doc> {
    Rc::new(d)
}

/// Suspend a document computation (a thunk). The closure runs at most once.
fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
        Box::new(f),
    ))))))
}

/// Force a document to its outermost non-`Lazy` constructor (shallow clone —
/// children stay shared via `Rc`). Thunks are computed once and memoized.
fn force(d: &Doc) -> Doc {
    let mut cur = d.clone();
    loop {
        let l = match &cur {
            Lazy(l) => l.clone(),
            _ => return cur,
        };
        if let LazyState::Forced(v) = &*l.0.borrow() {
            cur = v.clone();
            continue;
        }
        let f = match &mut *l.0.borrow_mut() {
            LazyState::Pending(f) => f.take().expect("re-entrant force"),
            LazyState::Forced(v) => {
                cur = v.clone();
                continue;
            }
        };
        let v = f();
        // The computed value may itself be a thunk; keep forcing, but memoize
        // the final value on every thunk along the chain.
        let mut inner = v.clone();
        while let Lazy(li) = &force_step(&mut inner) {
            let _ = li;
        }
        *l.0.borrow_mut() = LazyState::Forced(inner.clone());
        return inner;
    }
}

/// One forcing step helper for [`force`]: if `*d` is a computed-or-pending
/// thunk, replace it by its value; returns the current value for inspection.
fn force_step(d: &mut Doc) -> Doc {
    if let Lazy(_) = d {
        let v = force(&d.clone());
        *d = v;
    }
    d.clone()
}

